// 30MF系の素体・武装名からカテゴリ/勢力を推定（DBに無いメタを名称ベースで付与）
(function () {
  var FACTIONS = ['ローザン', 'リーベル'];
  function mfMeta(it) {
    if (it.b !== '30MF') return { cat: null, faction: null };
    var n = it.n;
    var faction = null;
    for (var i = 0; i < FACTIONS.length; i++) if (n.includes(FACTIONS[i])) faction = FACTIONS[i] + (n.includes(FACTIONS[i] + '帝国') ? '帝国' : '共和国');
    if (n.includes('ローザン')) faction = 'ローザン帝国';
    if (n.includes('リーベル')) faction = 'リーベル共和国';
    var cat = 'キャラクター';
    if (/アーマー|クラスアップ/.test(n)) cat = 'クラスアップアーマー';
    else if (/ウェポン|武器|ウエポン/.test(n) || it.s === 'weapon') cat = 'ウェポン';
    else if (/ストラクチャー|背景|シーン|ベース台/.test(n)) cat = 'カスタマイズストラクチャー';
    else if (/アイテムショップ|小物|アクセサリ/.test(n)) cat = 'アイテムショップ';
    else if (it.k === 'option') cat = 'クラスアップアーマー';
    return { cat: cat, faction: faction };
  }
  window.ITEMS.forEach(function (it) {
    var m = mfMeta(it);
    it.mfcat = m.cat;
    it.faction = m.faction;
  });
})();
